parameters.jsCode:
const items = $input.all();

return items.map(item => {
  const data = item.json;

  // --- Parse author field ---
  let authorData = data.author;
  if (typeof authorData === 'string') {
    try {
      authorData = JSON.parse(authorData);
    } catch {
      authorData = {};
    }
  }
  const authorName = authorData.name || null;

  // --- Parse posted_at field ---
  let postedAtData = data.posted_at;
  if (typeof postedAtData === 'string') {
    try {
      postedAtData = JSON.parse(postedAtData);
    } catch {
      postedAtData = {};
    }
  }

  // Extract only the date part (before any space)
  let postedDate = null;
  if (postedAtData.date) {
    postedDate = postedAtData.date.split(' ')[0];
  }

  // --- Return cleaned result ---
  return {
    json: {
      ...data,
      author_name: authorName,
      posted_date: postedDate
    }
  };
});
